NodeLibrary.push({
    nodetype: 'input/constant',
    help: {
    "summary": "A fundamental utility node that outputs a static integer value. It acts as a hardcoded parameter provider for other nodes.",
    "inlets": {
        "val": "Internal state value. Although it has an inlet, it is primarily set using the text box in the node's UI."
    },
    "outlets": {
        "out": "The constant integer value (e.g., 440, 9, 1023)."
    },
    "usage": "Use this to define fixed hardware configurations. For example, if an 'Analog In' node needs to know which pin to read, connect a Constant node with the value 0 (for A0) to its 'pin' inlet. Range: -32768 to 32767."
},
    nodeclass: "Const",
    is_constant: true,
    description: "Generates a constant value or represents a physical Pin.",
    mozzi: {
        rate: "control"
    },
    renderer: {
        'html': function(body, node) {
            if (!node.data) node.data = { val: "0" };
            if (!node._ui) {
                var inp = document.createElement('input'); inp.type = 'text'; inp.className = 'mozzi-constant-input'; inp.value = node.data.val;
                inp.oninput = function() { node.data.val = this.value; if(node.inlets['val']) node.inlets['val'].receive(this.value); };
                body.appendChild(inp); node._ui = inp;
                
                var syncConstant = function() {
                    if (node.inlets && node.inlets['val'] && node.inlets['val'].event && typeof node.inlets['val'].event.onValue === 'function') {
                        node.inlets['val'].event.onValue(function(val) {
                            if (node.data.val !== val) {
                                node.data.val = val;
                                inp.value = val;
                            }
                        });
                    } else {
                        setTimeout(syncConstant, 100);
                    }
                };
                syncConstant();
            }
        }
    },
    rpdnode: {
    "title": "Constant",
    "inlets": {
        "val": {
            "type": "mozziflow/string",
            "default": "0",
            "hidden": true
        }
    },
    "outlets": {
        "out": {
            "type": "mozziflow/string"
        }
    }
}
});

