NodeLibrary.push({
    nodetype: 'input/float_constant',
    nodeclass: "FloatConst",
    is_constant: true,
    description: "Generates a constant decimal value.",
    mozzi: {
        rate: "control"
    },
    renderer: {
        'html': function(body, node) {
            if (!node.data) node.data = { value: "1.0" };
            if (!node._ui) {
                var inp = document.createElement('input'); 
                inp.type = 'text'; inp.className = 'mozzi-constant-input'; 
                inp.style.color = '#0066FF'; inp.style.borderColor = '#0066FF';
                inp.value = node.data.value;
                inp.oninput = function() { 
                    node.data.value = this.value; 
                    if(node.inlets['val']) node.inlets['val'].receive(this.value); 
                };
                body.appendChild(inp); node._ui = inp;
                
                var syncConstant = function() {
                    if (node.inlets && node.inlets['val'] && node.inlets['val'].event && typeof node.inlets['val'].event.onValue === 'function') {
                        node.inlets['val'].event.onValue(function(val) {
                            if (node.data.value !== val) {
                                node.data.value = val;
                                inp.value = val;
                            }
                        });
                    } else { setTimeout(syncConstant, 100); }
                };
                syncConstant();
            }
        }
    },
    rpdnode: {
        "title": "Float Const",
        "inlets": { "val": { "type": "mozziflow/float_32", "default": "1.0", "hidden": true } },
        "outlets": { "out": { "type": "mozziflow/float_32" } }
    }
});